require "event.BaseEvent"

HidingEvent = class("HidingEvent", BaseEvent)

function HidingEvent:onTriggered(player)
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgInvisibility())
    local time = 0
    if self.config.time ~= -1 then
        time = self.config.time
    end
    player:addEffect(PotionID.INVISIBILITY, time or 0, 1)
    player.isHiding = true
    player.HidingTimer = LuaTimer:schedule(function (userId)
        local pPlayer = PlayerManager:getPlayerByUserId(userId)
        if pPlayer == nil then
            return
        end
        pPlayer.isHiding = false
        pPlayer.HidingTimer = 0
    end, time * 1000, nil, player.userId)
end

return HidingEvent